/**
 * Deterministic orchestration test for chaos-style juggling composition.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/juggling-chaos-orchestration.test.ts
 */

import assert from 'node:assert';
import {
  JUGGLING_COMPOSITION_PROPOSERS,
  JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS,
  orchestrateJugglingChaosComposition,
  type JugglingChaosOrchestrationBundle,
  type JugglingChaosOrchestrationInput,
} from '../juggling-chaos-orchestration';

const CORPUS_INPUT: JugglingChaosOrchestrationInput = {
  period: 2,
  generatedAt: '2026-04-10T00:00:00.000Z',
  source: 'test-suite',
  seed: 20260410,
  populationSize: 14,
  generations: 6,
  throwsPerPattern: 10,
  corpus: [
    {
      patternId: 'cascade-a',
      styleTags: ['balanced', 'classic'],
      throws: [
        { beat: 0, fromHand: 'left', flightBeats: 3, lane: 0, angleDeg: 8, speed: 7.2, label: 'a' },
        { beat: 1, fromHand: 'right', flightBeats: 3, lane: 0, angleDeg: 8, speed: 7.1, label: 'b' },
        { beat: 0, fromHand: 'left', flightBeats: 3, lane: 0, angleDeg: 9, speed: 7.3, label: 'c' },
        { beat: 1, fromHand: 'right', flightBeats: 3, lane: 0, angleDeg: 8, speed: 7.2, label: 'd' },
      ],
    },
    {
      patternId: 'multiplex-b',
      styleTags: ['asymmetric', 'machine'],
      throws: [
        { beat: 0, fromHand: 'left', flightBeats: 2, lane: 0, angleDeg: 6, speed: 7.0, label: 'e' },
        { beat: 0, fromHand: 'left', flightBeats: 3, lane: 1, angleDeg: 30, speed: 10.4, label: 'f' },
        { beat: 1, fromHand: 'right', flightBeats: 2, lane: 0, angleDeg: 7, speed: 7.1, label: 'g' },
        { beat: 1, fromHand: 'right', flightBeats: 3, lane: 1, angleDeg: 12, speed: 8.2, label: 'h' },
      ],
    },
    {
      patternId: 'swing-c',
      styleTags: ['flow', 'expressive'],
      throws: [
        { beat: 0, fromHand: 'left', flightBeats: 4, lane: 0, angleDeg: 16, speed: 8.0, label: 'i' },
        { beat: 1, fromHand: 'right', flightBeats: 2, lane: 0, angleDeg: 5, speed: 6.8, label: 'j' },
        { beat: 0, fromHand: 'left', flightBeats: 3, lane: 1, angleDeg: 22, speed: 8.9, label: 'k' },
        { beat: 1, fromHand: 'right', flightBeats: 3, lane: 0, angleDeg: 9, speed: 7.0, label: 'l' },
      ],
    },
  ],
  machineOnlyMultiplexThreshold: 2,
  machineOnlyAngleThresholdDeg: 12,
  machineOnlySpeedRatioThreshold: 1.3,
};

function assertCommon(
  bundle: JugglingChaosOrchestrationBundle,
  expectedProposer: JugglingChaosOrchestrationBundle['configuration']['proposer']
): void {
  assert.strictEqual(bundle.generatedAt, '2026-04-10T00:00:00.000Z');
  assert.strictEqual(bundle.source, 'test-suite');
  assert.strictEqual(bundle.seed, 20260410);
  assert.strictEqual(bundle.period, 2);
  assert.strictEqual(bundle.configuration.populationSize, 14);
  assert.strictEqual(bundle.configuration.generations, 6);
  assert.strictEqual(bundle.configuration.throwsPerPattern, 10);
  assert.strictEqual(bundle.configuration.proposer, expectedProposer);
  assert.ok(bundle.configuration.gaitProfile.stepPeriodBeats >= 1);
  assert.ok(bundle.configuration.gaitProfile.comFlightTargetBeats >= 1);
  assert.ok(bundle.configuration.gaitProfile.comFlightToleranceBeats >= 0.25);
  assert.ok(bundle.configuration.gaitProfile.lateralBias >= 0);
  assert.ok(bundle.configuration.gaitProfile.lateralBias <= 1);
  assert.ok(bundle.configuration.gaitProfile.uncertaintySigma >= 0);
  assert.ok(bundle.configuration.gaitProfile.uncertaintySigma <= 1);
  assert.ok(bundle.configuration.mpc.horizonBeats >= 1);
  assert.ok(bundle.configuration.mpc.solverBudgetMs >= 1);
  assert.ok(bundle.configuration.mpc.restartCount >= 0);
  assert.strictEqual(bundle.corpusDigest.patternCount, 3);
  assert.ok(bundle.corpusDigest.uniqueThrowTemplateCount >= 8);
  assert.ok(bundle.generationSummaries.length === 6);
  assert.ok(bundle.finalists.length >= 1);

  for (const theoremId of JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS) {
    assert.ok(bundle.theoremIds.includes(theoremId));
  }

  for (let index = 1; index < bundle.generationSummaries.length; index += 1) {
    const previous = bundle.generationSummaries[index - 1];
    const current = bundle.generationSummaries[index];
    if (!previous || !current) {
      continue;
    }
    assert.ok(current.bestScore >= previous.bestScore);
    assert.ok(current.convergenceSlope >= 0);
    assert.ok(current.proposerMix.markov >= 0);
    assert.ok(current.proposerMix.markov <= 1);
    assert.ok(current.proposerMix.corpusRemix >= 0);
    assert.ok(current.proposerMix.corpusRemix <= 1);
    assert.ok(current.proposerMix.eliteCarry >= 0);
    assert.ok(current.proposerMix.eliteCarry <= 1);
    assert.ok(
      Math.abs(
        current.proposerMix.markov +
          current.proposerMix.corpusRemix +
          current.proposerMix.eliteCarry -
          1
      ) < 0.0002
    );
    assert.ok(current.meanMutationEvents >= 0);
    assert.ok(current.mpc.horizonPressure >= 0);
    assert.ok(current.mpc.horizonPressure <= 1);
    assert.ok(current.mpc.nonConvexRisk >= 0);
    assert.ok(current.mpc.nonConvexRisk <= 1);
    assert.ok(current.mpc.dimensionalLoad >= 0);
    assert.ok(current.mpc.dimensionalLoad <= 1);
    assert.ok(current.mpc.uncertaintyLoad >= 0);
    assert.ok(current.mpc.uncertaintyLoad <= 1);
  }

  assert.ok(bundle.winner.throws.length === 10);
  assert.ok(bundle.winner.orbit.aggregate.throwCount === 10);
  assert.ok(bundle.winner.score.validity >= 0);
  assert.ok(bundle.winner.score.validity <= 1);
  assert.ok(bundle.winner.score.flow >= 0);
  assert.ok(bundle.winner.score.flow <= 1);
  assert.ok(bundle.winner.score.gaitCoupling >= 0);
  assert.ok(bundle.winner.score.gaitCoupling <= 1);
  assert.ok(bundle.winner.score.novelty >= 0);
  assert.ok(bundle.winner.score.novelty <= 1);
  assert.ok(bundle.winner.score.machineSuitability >= 0);
  assert.ok(bundle.winner.score.machineSuitability <= 1);
  assert.ok(bundle.winner.score.mpc.horizonPressure >= 0);
  assert.ok(bundle.winner.score.mpc.horizonPressure <= 1);
  assert.ok(bundle.winner.score.mpc.nonConvexRisk >= 0);
  assert.ok(bundle.winner.score.mpc.nonConvexRisk <= 1);
  assert.ok(bundle.winner.score.mpc.dimensionalLoad >= 0);
  assert.ok(bundle.winner.score.mpc.dimensionalLoad <= 1);
  assert.ok(bundle.winner.score.mpc.uncertaintyLoad >= 0);
  assert.ok(bundle.winner.score.mpc.uncertaintyLoad <= 1);
  assert.ok(bundle.winner.score.mpc.warmStartGain >= 0);
  assert.ok(bundle.winner.score.mpc.warmStartGain <= 1);
  assert.ok(bundle.winner.score.total >= 0);
  assert.ok(bundle.winner.score.total <= 1);
}

const markovDefault = orchestrateJugglingChaosComposition(CORPUS_INPUT);
const markovExplicit = orchestrateJugglingChaosComposition({
  ...CORPUS_INPUT,
  proposer: 'markov',
});
assert.deepStrictEqual(markovDefault, markovExplicit);
assertCommon(markovDefault, 'markov');

for (const proposer of JUGGLING_COMPOSITION_PROPOSERS) {
  const deterministicA = orchestrateJugglingChaosComposition({
    ...CORPUS_INPUT,
    proposer,
  });
  const deterministicB = orchestrateJugglingChaosComposition({
    ...CORPUS_INPUT,
    proposer,
  });
  assert.deepStrictEqual(deterministicA, deterministicB);
  assertCommon(deterministicA, proposer);
}

console.log('juggling-chaos-orchestration: all tests passed');
